export function getBlogContent(city: string, slug: string): BlogContent | undefined {
    return contentMap[city]?.[slug];
}

export function getAllBlogEntries() {
    return Object.entries(contentMap).flatMap(([city, entries]) =>
        Object.keys(entries).map((slug) => ({ city, slug }))
    );
}
